function LFightIdleLogCtrl:LFightIdleLogCtrl()
	self._useSkillStr = ccClientText(10900) or ""
	self._hurtStr = ccClientText(10901) or ""
	self._areaClear1 = ccClientText(10902) or ""
	self._areaClear2 = ccClientText(10903) or ""
	self._strPrepareToBattle = ccClientText(10916) or ""

	self._isLogOpen = false
end

function LFightIdleLogCtrl:IsLogOpen()
	return self._isLogOpen
end


