---@param fromObj LFightIdleObject
---@param toObj LFightIdleObject
function LFightIdleLogCtrl:LogHurt(fromObj,toObj,hurt)
	if not self:IsLogOpen() then return end

	local str = self._hurtStr
	str = string.gsub(str,"{1}",fromObj:GetObjName())
	str = string.gsub(str,"{2}",toObj:GetObjName())
	str = string.gsub(str,"{3}",LUtil.FormatColorStr(tostring(hurt),"red"))
	local msgData =
	{
		msgType =1,
		text =str
	}
	FireEvent(EventNames.ON_PRODUCE_HANG_MSG,msgData)
end

