function LFightIdleLogCtrl:InitData(sayCd)
	self._sayCd = sayCd
	local cd = math.random(sayCd.min,sayCd.max)
	self._nextTime = Time.time+ cd
end

function LFightIdleLogCtrl:OnRun(time)
	if self._nextTime and self._nextTime< time then
		self:LogSaySomething()
	end
end


function LFightIdleLogCtrl:LogPrepareToBattle()
	if not self:IsLogOpen() then return end

	local msgData =
	{
		msgType =1,
		text = self._strPrepareToBattle
	}
	FireEvent(EventNames.ON_PRODUCE_HANG_MSG,msgData)
end

function LFightIdleLogCtrl:LogSaySomething()
	if not self:IsLogOpen() then return end

	local cd = math.random(self._sayCd.min,self._sayCd.max)
	self._nextTime = self._manager:GetTime()+ cd
	local objCtrl = self._manager:GetObjCtrl()
	local monsterName = objCtrl:GetRandomMonsterName()
	if not monsterName then
		return
	end
	local words = gModelInstance:GetSayingWord(monsterName)
	if not words then
		return
	end
	local msgData =
	{
		msgType =1,
		text =words,
	}
	FireEvent(EventNames.ON_PRODUCE_HANG_MSG,msgData)
end

function LFightIdleLogCtrl:ShowBubbleLog(obj, str)
	if not self:IsLogOpen() then return end

	local heroName = obj:GetObjName()
	local words = string.replace(ccClientText(10755),heroName,str)
	local msgData =
	{
		msgType =1,
		text =words,
	}
	FireEvent(EventNames.ON_PRODUCE_HANG_MSG,msgData)
end

